다음 C 언어 프로그램이 실행되었을 때, 실행 결과는?

#include <stdio.h>
#include <stdlib.h>

int main(int argc, char* argv[]) {
    int arr[2][3] = { 1, 2, 3, 4, 5, 6 };
    int (*p)[3] = NULL;
    p = arr;
    printf("%d, ", *(p[0] + 1) + *(p[1] + 2));
    printf("%d", *(*(p + 1) + 0) + *(*(p + 1) + 1));
    return 0;
}

다음과 같은 형태로 임계 구역의 접근을 제어하는 상호배제 기법은?

P(S):
    while S <= 0 do skip;
    S := S - 1;
V(S):
    S := S + 1;

다음 C 언어 프로그램이 실행되었을 때, 실행 결과는?

#include <stdio.h>
#include <stdlib.h>

int main(int argc, char* argv[]) {
    int i = 0;
    while (1) {
        if (i == 4) {
            break;
        }
        ++i;
    }
    printf("i = %d", i);
    return 0;
}

다음 Java 프로그램이 실행되었을 때, 실행 결과는?

public class Ape {
    static void rs(char a[]) {
        for (int i = 0; i < a.length; i++)
            if (a[i] == 'B')
                a[i] = 'C';
            else if (i == a.length - 1)
                a[i] = a[i - 1];
            else
                a[i] = a[i + 1];
    }

    static void pca(char a[]) {
        for (int i = 0; i < a.length; i++)
            System.out.print(a[i]);
        System.out.println();
    }

    public static void main(String[] args) {
        char c[] = {'A', 'B', 'D', 'D', 'A', 'B', 'C'};
        rs(c);
        pca(c);
    }
}

다음 C 언어 프로그램이 실행되었을 때, 실행 결과는?

#include <stdio.h>
#include <stdlib.h>

int main(int argc, char* argv[]) {
    char str1[20] = "KOREA";
    char str2[20] = "LOVE";
    char* p1 = NULL;
    char* p2 = NULL;
    p1 = str1;
    p2 = str2;
    str1[1] = p2[2];
    str2[3] = p1[4];
    strcat(str1, str2);
    printf("%c", *(p1 + 2));
    return 0;
}
